'use strict';

// MODULES //

import stride2offset from '@stdlib/strided/base/stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Multiplies each element in a double-precision floating-point strided array by a scalar constant and adds a scalar constant to each result.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {number} alpha - first scalar constant
* @param {number} beta - second scalar constant
* @param {Float64Array} x - input array
* @param {integer} strideX - stride length
* @returns {Float64Array} input array
*
* @example
* import Float64Array from '@stdlib/array/float64';
*
* var x = new Float64Array( [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ] );
*
* daxpb( x.length, 5.0, 3.0, x, 1 );
* // x => <Float64Array>[ -7.0, 8.0, 18.0, -22.0, 23.0, 3.0, -2.0, -12.0 ]
*/
function daxpb( N, alpha, beta, x, strideX ) {
	return ndarray( N, alpha, beta, x, strideX, stride2offset( N, strideX ) );
}


// EXPORTS //

export default daxpb;
